        return False

    if n == 0:
        return True

    # Binary search for the square root
    left, right = 0, n

    while left <= right:
        mid = (left + right) // 2
        square = mid * mid

        if square == n:
            return True
        elif square < n:
            left = mid + 1
        else:
            right = mid - 1

